import React, { useState, useEffect, useTransition, useActionState, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import './AdminDashboard.css';
import API from '../context/API';

axios.defaults.baseURL = API;
// Create user action
const createUserAction = async (prevState, formData) => {
  const username = formData.get('username');
  const email = formData.get('email');
  const password = formData.get('password');
  const role = formData.get('role');
  return { username, email, password, role };
};

const AdminDashboard = () => {
  const { user } = useAuth();
  const [users, setUsers] = useState([]);
  const [logs, setLogs] = useState([]);
  const [backups, setBackups] = useState([]);
  const [showLogs, setShowLogs] = useState(false);
  const [loading, setLoading] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [isPending, startTransition] = useTransition();

  useEffect(() => {
    fetchAllData();
  }, []);

  const fetchAllData = useCallback(async () => {
    await Promise.all([
      fetchUsers(),
      fetchLogs(),
      fetchBackups()
    ]);
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get('/api/users');
      setUsers(res.data);
    } catch (error) {
      console.error('Error fetching users:', error);
    }
  };

  const fetchLogs = async () => {
    try {
      const res = await axios.get('/api/logs');
      setLogs(res.data);
    } catch (error) {
      console.error('Error fetching logs:', error);
    }
  };

  const fetchBackups = async () => {
    try {
      const res = await axios.get('/api/backup');
      setBackups(res.data);
    } catch (error) {
      console.error('Error fetching backups:', error);
    }
  };

  const createBackup = async () => {
    if (!window.confirm('Create manual backup?')) return;
    setLoading(true);
    try {
      await axios.post('/api/backup/manual');
      await fetchBackups();
      alert('Backup created successfully');
    } catch (error) {
      alert('Error creating backup: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const restoreBackup = async (backupId) => {
    if (!window.confirm('Restore this backup? This will overwrite all current data!')) return;
    setLoading(true);
    try {
      await axios.post(`/api/backup/restore/${backupId}`);
      alert('Backup restored successfully');
      await fetchAllData();
    } catch (error) {
      alert('Error restoring backup: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const deleteBackup = async (backupId) => {
    if (!window.confirm('Delete this backup?')) return;
    try {
      await axios.delete(`/api/backup/${backupId}`);
      await fetchBackups();
    } catch (error) {
      alert('Error deleting backup: ' + (error.response?.data?.error || error.message));
    }
  };

  const updateUser = async (userId, data) => {
    try {
      await axios.put(`/api/users/${userId}`, data);
      await fetchUsers();
      setEditingUser(null);
    } catch (error) {
      alert('Error updating user: ' + (error.response?.data?.error || error.message));
    }
  };

  const deleteUser = async (userId) => {
    if (!window.confirm('Delete this user?')) return;
    try {
      await axios.delete(`/api/users/${userId}`);
      await fetchUsers();
    } catch (error) {
      alert('Error deleting user: ' + (error.response?.data?.error || error.message));
    }
  };

  const handleCreateUser = async (e) => {
    e.preventDefault();
    const form = e.target;
    const data = {
      username: form.username.value,
      email: form.email.value,
      password: form.password.value,
      role: form.role.value
    };
    
    startTransition(async () => {
      try {
        await axios.post('/api/users', data);
        await fetchUsers();
        form.reset();
      } catch (error) {
        alert('Error creating user: ' + (error.response?.data?.error || error.message));
      }
    });
  };

  if (!user || user.role !== 'admin') {
    return (
      <div className="admin-access-denied">
        <div className="admin-access-content">
          <div className="access-icon">⛔</div>
          <h2>Access Denied</h2>
          <p>Admin privileges required</p>
          <button className="btn" onClick={() => window.location.href = '/board'}>
            ← Back to Board
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="admin-container">
      <div className="admin-header">
        <h2>⚙️ Admin Dashboard</h2>
        <div className="admin-actions">
          <button className="btn" onClick={() => window.location.href = '/board'}>← Back to Board</button>
          <button className="btn btn-warning" onClick={createBackup} disabled={loading || isPending}>
            {loading ? '⏳ Creating...' : '💾 Create Backup'}
          </button>
          <button className="btn btn-info" onClick={() => setShowLogs(!showLogs)}>
            📋 {showLogs ? 'Hide Logs' : 'Show Logs'}
          </button>
        </div>
      </div>

      <div className="admin-content">
        <div className="admin-section">
          <h3>👥 Users</h3>
          <div className="user-grid">
            {users.map(u => (
              <div key={u._id} className="user-card">
                {editingUser === u._id ? (
                  <div className="user-edit">
                    <input
                      type="text"
                      defaultValue={u.username}
                      ref={el => el && (el.dataset.field = 'username')}
                      placeholder="Username"
                    />
                    <input
                      type="email"
                      defaultValue={u.email}
                      ref={el => el && (el.dataset.field = 'email')}
                      placeholder="Email"
                    />
                    <select defaultValue={u.role}>
                      <option value="user">User</option>
                      <option value="admin">Admin</option>
                    </select>
                    <label>
                      <input type="checkbox" defaultChecked={u.isActive} /> Active
                    </label>
                    <div className="edit-actions">
                      <button
                        className="btn btn-success"
                        onClick={() => {
                          const inputs = document.querySelectorAll('.user-edit input, .user-edit select');
                          const data = {};
                          inputs.forEach(el => {
                            if (el.type === 'checkbox') {
                              data[el.dataset.field || 'isActive'] = el.checked;
                            } else if (el.dataset.field) {
                              data[el.dataset.field] = el.value;
                            } else if (el.tagName === 'SELECT') {
                              data.role = el.value;
                            }
                          });
                          const checkbox = document.querySelector('.user-edit input[type="checkbox"]');
                          data.isActive = checkbox.checked;
                          updateUser(u._id, data);
                        }}
                      >
                        Save
                      </button>
                      <button className="btn" onClick={() => setEditingUser(null)}>Cancel</button>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="user-info">
                      <strong>{u.username}</strong>
                      <span className="user-email">{u.email}</span>
                      <span className={`user-role ${u.role}`}>{u.role}</span>
                      <span className={`user-status ${u.isActive ? 'active' : 'inactive'}`}>
                        {u.isActive ? '🟢 Active' : '🔴 Inactive'}
                      </span>
                      {u.lastLogin && (
                        <span className="user-last-login">Last login: {new Date(u.lastLogin).toLocaleString()}</span>
                      )}
                      {u.lastLoginIP && (
                        <span className="user-ip">IP: {u.lastLoginIP}</span>
                      )}
                      <span className="user-login-count">Logins: {u.loginHistory?.length || 0}</span>
                    </div>
                    <div className="user-actions">
                      <button className="btn btn-info" onClick={() => setEditingUser(u._id)}>✏️ Edit</button>
                      <button className="btn btn-danger" onClick={() => deleteUser(u._id)}>🗑️</button>
                    </div>
                  </>
                )}
              </div>
            ))}
          </div>
        </div>

        <div className="admin-section">
          <h3>➕ Create New User</h3>
          <form className="create-user-form" onSubmit={handleCreateUser}>
            <input type="text" name="username" placeholder="Username" required />
            <input type="email" name="email" placeholder="Email" required />
            <input type="password" name="password" placeholder="Password" required minLength="6" />
            <select name="role">
              <option value="user">User</option>
              <option value="admin">Admin</option>
            </select>
            <button type="submit" className="btn btn-success" disabled={isPending}>
              {isPending ? 'Creating...' : 'Create User'}
            </button>
          </form>
        </div>

        {showLogs && (
          <div className="admin-section">
            <h3>📋 Recent Logs</h3>
            <div className="logs-container">
              {logs.map(log => (
                <div key={log._id} className="log-entry">
                  <span className="log-time">{new Date(log.timestamp).toLocaleString()}</span>
                  <span className="log-user">{log.username || 'System'}</span>
                  <span className={`log-action ${log.action}`}>{log.action}</span>
                  <span className="log-details">{log.details}</span>
                  <span className="log-ip">{log.ip}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="admin-section">
          <h3>💾 Backups</h3>
          <div className="backups-grid">
            {backups.map(b => (
              <div key={b._id} className="backup-card">
                <span className="backup-name">{b.filename}</span>
                <span className="backup-size">{(b.size / 1024).toFixed(1)} KB</span>
                <span className="backup-date">{new Date(b.createdAt).toLocaleString()}</span>
                {b.isManual && <span className="backup-type manual">Manual</span>}
                {!b.isManual && <span className="backup-type auto">Auto</span>}
                <div className="backup-actions">
                  <button className="btn btn-warning" onClick={() => restoreBackup(b._id)} disabled={loading}>
                    ↩️ Restore
                  </button>
                  <button className="btn btn-danger" onClick={() => deleteBackup(b._id)}>🗑️</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;